// ============================================================
// MÓDULO AUTH — Autenticación y sesiones con localStorage
// ============================================================
const Auth = (() => {
  const USERS_KEY = 'cp_users';
  const SESSION_KEY = 'cp_session';

  const DEFAULT_ADMIN = {
    id: 'admin_001',
    username: 'admin',
    password: btoa('Admin2025!'),
    role: 'admin',
    displayName: 'Administrador',
    avatar: '🌿',
    createdAt: new Date().toISOString()
  };

  function init() {
    const users = getUsers();
    if (!users.find(u => u.username === 'admin')) {
      users.push(DEFAULT_ADMIN);
      saveUsers(users);
    }
  }
  function getUsers() { return JSON.parse(localStorage.getItem(USERS_KEY) || '[]'); }
  function saveUsers(u) { localStorage.setItem(USERS_KEY, JSON.stringify(u)); }
  function getCurrentSession() { return JSON.parse(localStorage.getItem(SESSION_KEY) || 'null'); }
  function saveSession(user) {
    const s = { id: user.id, username: user.username, role: user.role, displayName: user.displayName, avatar: user.avatar };
    localStorage.setItem(SESSION_KEY, JSON.stringify(s));
    return s;
  }
  function clearSession() { localStorage.removeItem(SESSION_KEY); }
  function register(username, password, displayName) {
    const users = getUsers();
    if (users.find(u => u.username === username.trim().toLowerCase()))
      return { success: false, error: 'El usuario ya existe.' };
    if (password.length < 6)
      return { success: false, error: 'La contraseña debe tener al menos 6 caracteres.' };
    const u = { id: 'user_' + Date.now(), username: username.trim().toLowerCase(), password: btoa(password), role: 'viewer', displayName: displayName.trim() || username, avatar: '🌱', createdAt: new Date().toISOString() };
    users.push(u);
    saveUsers(users);
    return { success: true, user: u };
  }
  function login(username, password) {
    const users = getUsers();
    const user = users.find(u => u.username === username.trim().toLowerCase() && u.password === btoa(password));
    if (!user) return { success: false, error: 'Usuario o contraseña incorrectos.' };
    return { success: true, session: saveSession(user) };
  }
  function logout() { clearSession(); }
  function isLoggedIn() { return !!getCurrentSession(); }
  function isAdmin() { const s = getCurrentSession(); return s && s.role === 'admin'; }
  return { init, register, login, logout, isLoggedIn, isAdmin, getCurrentSession, getUsers };
})();

// ============================================================
// MÓDULO BOOKS — Lee metadatos de cp_books_meta (IndexedDB para archivos)
// KEY compartida con admin.html: 'cp_books_meta'
// ============================================================
const Books = (() => {
  const META_KEY = 'cp_books_meta';

  // IndexedDB — misma BD que admin.html
  let _idb = null;
  function openIDB() {
    if (_idb) return Promise.resolve(_idb);
    return new Promise((res, rej) => {
      const r = indexedDB.open('ClickPlanetDB', 2);
      r.onupgradeneeded = e => {
        const db = e.target.result;
        if (!db.objectStoreNames.contains('files'))
          db.createObjectStore('files', { keyPath: 'id' });
      };
      r.onsuccess = e => { _idb = e.target.result; res(_idb); };
      r.onerror   = e => rej(e.target.error);
    });
  }

  async function getFileURL(fileId) {
    if (!fileId) return null;
    try {
      const db = await openIDB();
      return new Promise(res => {
        const req = db.transaction('files', 'readonly').objectStore('files').get(fileId);
        req.onsuccess = () => {
          const record = req.result;
          if (!record) { res(null); return; }
          try {
            // El admin guarda { data: ArrayBuffer, type: string }
            const entry = record.blob || record;
            const data  = entry.data  || entry;
            const type  = entry.type  || 'application/octet-stream';
            const blob  = new Blob([data], { type });
            res(URL.createObjectURL(blob));
          } catch(e) { res(null); }
        };
        req.onerror = () => res(null);
      });
    } catch(e) { return null; }
  }

  // IMPORTANTE: NUNCA sobreescribe lo que guardó el admin
  // Solo devuelve array vacío si no hay nada — la UI mostrará "vuelve pronto"
  function getBooks() {
    try {
      const s = localStorage.getItem(META_KEY);
      if (s) {
        const parsed = JSON.parse(s);
        if (Array.isArray(parsed)) return parsed;
      }
    } catch(e) {}
    return []; // vacío — no toca localStorage
  }

  function saveBooks(b) { localStorage.setItem(META_KEY, JSON.stringify(b)); }
  function deleteBook(id) { saveBooks(getBooks().filter(b => b.id !== id)); }
  function fileToBase64(file) {
    return new Promise((res, rej) => {
      const r = new FileReader();
      r.onload = () => res(r.result);
      r.onerror = rej;
      r.readAsDataURL(file);
    });
  }
  return { getBooks, saveBooks, deleteBook, fileToBase64, getFileURL };
})();

// Exponer globalmente para uso en Noticias, Podcast, Enciclopedia, etc.
window.getFileURL = Books.getFileURL.bind(Books);

