function showToast(msg, isError = false) {
  const t = document.getElementById('cpToast');
  t.textContent = msg;
  t.className = 'cp-toast' + (isError ? ' error' : '');
  requestAnimationFrame(() => {
    t.classList.add('show');
    setTimeout(() => t.classList.remove('show'), 3000);
  });
}

