// SISTEMA ORIGINAL DE CLICK PLANET (script.js integrado)
// ============================================================
/* ─── Sistema de partículas estelar ─── */
function createParticles(containerId, count = 40) {
  const container = document.getElementById(containerId);
  if (!container) return;

  /* Limpiar cualquier contenido previo de partículas */
  container.querySelectorAll('.cp-starfield').forEach(el => el.remove());

  const wrap = document.createElement('div');
  wrap.className = 'cp-starfield';
  container.appendChild(wrap);

  const isMobile = window.innerWidth < 768;
  const W = window.innerWidth;
  const H = window.innerHeight;

  /* ── 1. Nebulosas de fondo (2-3 manchas de luz difusa) ── */
  const nebulas = isMobile ? 2 : 3;
  const nebulaColors = [
    'rgba(0,255,128,0.045)',
    'rgba(0,200,255,0.03)',
    'rgba(180,100,255,0.025)',
  ];
  for (let i = 0; i < nebulas; i++) {
    const nb = document.createElement('div');
    nb.className = 'cp-nebula';
    const size = 200 + Math.random() * 300;
    nb.style.cssText = `
      width:${size}px; height:${size}px;
      left:${Math.random()*90}%; top:${Math.random()*90}%;
      --nb-color:${nebulaColors[i % nebulaColors.length]};
      --nb-dur:${7 + Math.random()*6}s;
      --nb-delay:${Math.random()*4}s;
    `;
    wrap.appendChild(nb);
  }

  /* ── 2. Estrellas (3 tamaños: tiny, small, medium) ── */
  const starCount = isMobile ? 55 : 110;
  for (let i = 0; i < starCount; i++) {
    const star = document.createElement('div');
    const roll = Math.random();

    /* Tamaño: 70% tiny (1px), 25% small (2px), 5% medium (3px con halo) */
    let size, opMin, opMax, twScale, twDur, color;
    if (roll < 0.70) {
      size = 1;
      opMin = 0.1 + Math.random() * 0.2;
      opMax = 0.5 + Math.random() * 0.4;
      twScale = 1.2;
      twDur  = 2 + Math.random() * 4;
      color  = '#ffffff';
    } else if (roll < 0.95) {
      size = 2;
      opMin = 0.2 + Math.random() * 0.2;
      opMax = 0.7 + Math.random() * 0.3;
      twScale = 1.5;
      twDur  = 1.8 + Math.random() * 3;
      /* Leve tinte: blanco, verde-hielo, celeste */
      const tints = ['#ffffff','#c8ffec','#d0f8ff'];
      color = tints[Math.floor(Math.random()*tints.length)];
    } else {
      size = 3;
      opMin = 0.3;
      opMax = 1;
      twScale = 1.8;
      twDur  = 1.5 + Math.random() * 2;
      color  = '#00ffcc';
      star.classList.add('cp-star-halo');
      star.style.color = color;
    }

    star.className = 'cp-star' + (star.classList.contains('cp-star-halo') ? ' cp-star-halo' : '');
    star.style.cssText += `
      width:${size}px; height:${size}px;
      background:${color};
      left:${Math.random()*100}%;
      top:${Math.random()*100}%;
      --tw-dur:${twDur.toFixed(2)}s;
      --tw-delay:${(Math.random()*twDur).toFixed(2)}s;
      --op-min:${opMin.toFixed(2)};
      --op-max:${opMax.toFixed(2)};
      --tw-scale:${twScale};
    `;
    wrap.appendChild(star);
  }

  /* ── 3. Meteoros periódicos ── */
  const meteorAngles = [-25, -30, -20, -35];
  function launchMeteor() {
    const meteor = document.createElement('div');
    meteor.className = 'cp-meteor';

    const angle  = meteorAngles[Math.floor(Math.random() * meteorAngles.length)];
    const length = isMobile ? 80 + Math.random()*80 : 120 + Math.random()*140;
    const dur    = 1.4 + Math.random() * 0.8;

    /* Posición de inicio: borde superior o lado izquierdo */
    const startX = Math.random() * 85;
    const startY = Math.random() * 55;

    meteor.style.cssText = `
      width:${length}px;
      left:${startX}%;
      top:${startY}%;
      --m-angle:${angle}deg;
      --m-dur:${dur.toFixed(2)}s;
      --m-dist:${(length * 1.8).toFixed(0)}px;
      --m-delay:0s;
    `;
    wrap.appendChild(meteor);

    /* Eliminar el elemento tras la animación */
    setTimeout(() => meteor.remove(), (dur + 0.1) * 1000);
  }

  /* Primer meteoro al poco de cargar */
  setTimeout(launchMeteor, 1200 + Math.random() * 2000);

  /* Meteoros recurrentes cada 4-9 s */
  function scheduleMeteor() {
    const delay = 4000 + Math.random() * 5000;
    setTimeout(() => {
      /* Solo lanzar si el contenedor sigue en el DOM */
      if (document.getElementById(containerId)) {
        launchMeteor();
        /* A veces dos meteoros casi simultáneos */
        if (Math.random() < 0.25) setTimeout(launchMeteor, 300 + Math.random()*400);
        scheduleMeteor();
      }
    }, delay);
  }
  scheduleMeteor();
}

