// Aplicar configuración guardada por el admin
function applyConfig() {
  const cfg = JSON.parse(localStorage.getItem('cp_config') || 'null');
  if (!cfg) return;
  const h1 = document.querySelector('.welcome-screen h1');
  const p  = document.querySelector('.welcome-screen > p');
  const btn = document.getElementById('entrarBtn');
  const botImg = document.querySelector('.bot-img');
  const botFixed = document.querySelector('.bot');
  if (cfg.title && h1)    h1.textContent = cfg.title;
  if (cfg.subtitle && p)  p.textContent  = cfg.subtitle;
  if (cfg.btnText && btn) btn.textContent = cfg.btnText;
  // Logo: primero intentar desde IndexedDB (subido por admin), luego por URL
  if (cfg.logoFileId) {
    const req = indexedDB.open('ClickPlanetDB', 2);
    req.onsuccess = function() {
      const db = req.result;
      try {
        const tx = db.transaction('files', 'readonly');
        const store = tx.objectStore('files');
        const getReq = store.get(cfg.logoFileId);
        getReq.onsuccess = function() {
          if (getReq.result) {
            const entry = getReq.result.blob || getReq.result;
            const blob = new Blob([entry.data || entry], { type: entry.type || 'image/png' });
            const url = URL.createObjectURL(blob);
            if (botImg)   botImg.src   = url;
            if (botFixed) botFixed.src = url;
          }
        };
      } catch(e) {}
    };
  } else if (cfg.logoUrl) {
    if (botImg)   botImg.src   = cfg.logoUrl;
    if (botFixed) botFixed.src = cfg.logoUrl;
  }

  // ── Imagenes del menu principal desde config ──
  if (cfg.menuImages) {
    const cardMap = {
      cursos:      document.querySelector('.card[onclick="abrirCursos()"] img'),
      libros:      document.querySelector('.card[onclick="abrirLibros()"] img'),
      enciclopedia:document.querySelector('.card[onclick="abrirEnciclopedia()"] img'),
      podcast:     document.querySelector('.card[onclick="abrirPodcast()"] img'),
      naturaleza:  document.querySelector('.card[onclick="abrirNaturalezaLocal()"] img'),
      noticias:    document.querySelector('.card[onclick="abrirNoticiasVerde()"] img'),
      juegos:      document.querySelector('.card[onclick="abrirJuegos()"] img'),
      eventos:     document.querySelector('.card[onclick="abrirEventosAmbientales()"] img')
    };
    Object.keys(cardMap).forEach(key => {
      const img = cardMap[key];
      const src = cfg.menuImages[key];
      if (!img || !src) return;
      if (src.startsWith('idb://')) {
        // Cargar desde IndexedDB
        const fileId = src.replace('idb://', '');
        const req = indexedDB.open('ClickPlanetDB', 2);
        req.onsuccess = function() {
          const db = req.result;
          try {
            const tx = db.transaction('files', 'readonly');
            const getReq = tx.objectStore('files').get(fileId);
            getReq.onsuccess = function() {
              if (getReq.result) {
                const entry = getReq.result.blob || getReq.result;
                const blob = new Blob([entry.data || entry], { type: entry.type || 'image/png' });
                img.src = URL.createObjectURL(blob);
              }
            };
          } catch(e) {}
        };
      } else {
        img.src = src;
      }
    });
  }
}

