function getVideosData() {
  const stored = localStorage.getItem('cp_videos');
  if (stored) { try { const p = JSON.parse(stored); if (p.length) return p; } catch(e){} }
  return VIDEOS_DEFAULTS;
}

let videoActual = null;


// Fallback cuando YouTube bloquea el embedding
function _mostrarFallbackYT(wrap, videoId, titulo) {
  wrap._fallback = true;
  wrap.innerHTML = `
    <div style="position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;background:#0a0a0a;text-align:center;padding:20px;gap:12px;">
      <div style="font-size:2.5em;">🔒</div>
      <p style="color:rgba(255,255,255,.7);font-size:.9em;margin:0;line-height:1.4;">
        Este video no permite<br>reproducción en sitios externos.
      </p>
      <a href="https://www.youtube.com/watch?v=${videoId}" target="_blank"
         style="background:#ff0000;color:#fff;padding:10px 22px;border-radius:24px;text-decoration:none;font-weight:700;font-size:.9em;display:flex;align-items:center;gap:8px;margin-top:4px;">
        ▶ Ver en YouTube
      </a>
    </div>`;
}

function cargarTodosLosVideosMejorados(categoria = 'todos') {
  const grid = document.getElementById('videoGridMejorado');
  if (!grid) return;
  grid.innerHTML = '';
  const videosData = getVideosData();
  const filtrados  = categoria === 'todos' ? videosData : videosData.filter(v => v.category === categoria);

  if (!filtrados.length) {
    grid.innerHTML = `<div style="grid-column:1/-1;text-align:center;padding:60px 20px;color:rgba(255,255,255,.3);">
      <div style="font-size:3em;margin-bottom:12px">🎬</div><p>No hay videos en esta categoría.</p></div>`;
    return;
  }

  filtrados.forEach((video, i) => {
    const stars = '⭐'.repeat(video.stars || 4);
    const card  = document.createElement('div');
    card.className = 'video-card-mejorada';
    card.setAttribute('data-category', video.category);

    if (video.videoId) {
      // ── YouTube: botón play sobre imagen de portada → al clic carga iframe con autoplay ──
      const thumbUrl = `https://img.youtube.com/vi/${video.videoId}/hqdefault.jpg`;
      const _ytThumbId = 'ytimg-' + video.id;
      card.innerHTML = `
        <div class="playing-indicator">▶️ REPRODUCIENDO</div>
        <div style="position:relative;width:100%;padding-bottom:66%;border-radius:10px;overflow:hidden;margin-bottom:15px;background:#000;cursor:pointer;" id="vwrap-${video.id}">
          <img id="${_ytThumbId}" src="${thumbUrl}" style="position:absolute;inset:0;width:100%;height:100%;object-fit:cover;" onerror="this.style.display='none'">
          <div style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;background:rgba(0,0,0,.3);">
            <div style="width:64px;height:64px;background:#ff0000;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:1.5em;box-shadow:0 4px 20px rgba(0,0,0,.6);">▶</div>
          </div>
        </div>
        <div class="video-info">
          <h3 class="video-title">${video.emoji||'🎬'} ${video.title}</h3>
          <div class="estrellas">${stars}</div>
          <p class="video-description">${video.description||''}</p>
          <div class="video-meta">
            <span class="video-duration">⏱️ ${video.duration||'--'}</span>
            <span class="video-category">${video.emoji||'🎬'} ${getCategoryName(video.category)}</span>
          </div>
        </div>`;

      // Cargar miniatura personalizada del admin (sobreescribe la de YouTube)
      if (video.thumbFileId) {
        (async () => {
          try {
            const customThumb = await getFileURL(video.thumbFileId);
            if (!customThumb) return;
            const img = document.getElementById('ytimg-' + video.id);
            if (img) { img.src = customThumb; img.style.display = 'block'; }
          } catch(e) {}
        })();
      }

      // Un clic → reemplaza imagen por iframe con autoplay
      card.querySelector(`#vwrap-${video.id}`).addEventListener('click', function() {
        // Detener otro video si hay
        if (videoActual && videoActual !== card) {
          const prevWrap = videoActual.querySelector('[id^="vwrap-"]');
          if (prevWrap && prevWrap._iframe) {
            prevWrap.innerHTML = prevWrap._origHTML;
            delete prevWrap._iframe;
          }
          videoActual.classList.remove('playing');
        }
        // Cargar iframe con autoplay
        const wrap = this;
        wrap._origHTML = wrap.innerHTML;
        // Crear iframe y detectar error de embedding bloqueado
        const iframeEl = document.createElement('iframe');
        iframeEl.src = `https://www.youtube.com/embed/${video.videoId}?autoplay=1&rel=0&modestbranding=1`;
        iframeEl.allow = 'accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture';
        iframeEl.allowFullscreen = true;
        iframeEl.frameBorder = '0';
        iframeEl.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;border:none;border-radius:10px;';

        // Detectar error de embedding bloqueado
        iframeEl.addEventListener('load', function() {
          // Si el iframe no pudo cargar el video (error 153 u otro), mostrar alternativa
          setTimeout(() => {
            try {
              // Si el iframe tiene la clase de error de YT, mostramos fallback
              if (wrap._iframe) {
                // El iframe cargó — verificar si hay contenido real
              }
            } catch(e) {}
          }, 2500);
        });

        // Fallback por error — reemplazar con botón directo a YouTube
        iframeEl.addEventListener('error', function() {
          _mostrarFallbackYT(wrap, video.videoId, video.title);
        });

        wrap.innerHTML = '';
        wrap.appendChild(iframeEl);
        wrap._iframe = true;
        card.classList.add('playing');
        videoActual = card;
        playSound('click');

        // Timeout de seguridad: si en 4s sigue sin verse, mostrar enlace directo
        setTimeout(() => {
          if (wrap._iframe && !wrap._fallback) {
            // Agregar botón "¿No se ve? Abrir en YouTube" debajo del iframe
            const fallbackBtn = wrap.querySelector('.yt-fallback-btn');
            if (!fallbackBtn) {
              const btn = document.createElement('a');
              btn.href = `https://www.youtube.com/watch?v=${video.videoId}`;
              btn.target = '_blank';
              btn.className = 'yt-fallback-btn';
              btn.style.cssText = 'position:absolute;bottom:8px;left:50%;transform:translateX(-50%);background:rgba(255,0,0,.9);color:#fff;padding:6px 14px;border-radius:20px;font-size:.8em;text-decoration:none;white-space:nowrap;z-index:10;';
              btn.textContent = '▶ Abrir en YouTube';
              wrap.appendChild(btn);
            }
          }
        }, 4000);
      });

    } else if (video.videoFileId) {
      // ── Video local ──
      const _thumbId = 'vthumb-' + video.id;
      card.innerHTML = `
        <div style="position:relative;width:100%;padding-bottom:66%;border-radius:10px;overflow:hidden;margin-bottom:15px;background:#0a1a0c;cursor:pointer;"
             onclick="reproducirVideoLocal('${video.videoFileId}','${video.title}')">
          <div id="${_thumbId}" style="position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;background:#0a1a0c;background-size:cover;background-position:center;">
            <div style="font-size:3em;margin-bottom:8px">${video.emoji||'🎬'}</div>
            <div style="color:rgba(255,255,255,.6);font-size:.9em">▶ Tap para reproducir</div>
          </div>
        </div>
        <div class="video-info">
          <h3 class="video-title">${video.emoji||'🎬'} ${video.title}</h3>
          <div class="estrellas">${stars}</div>
          <p class="video-description">${video.description||''}</p>
          <div class="video-meta">
            <span class="video-duration">⏱️ ${video.duration||'--'}</span>
            <span class="video-category">${video.emoji||'🎬'} ${getCategoryName(video.category)}</span>
          </div>
        </div>`;

      // Cargar miniatura personalizada guardada desde el admin
      if (video.thumbFileId) {
        (async () => {
          try {
            const thumbUrl = await getFileURL(video.thumbFileId);
            if (!thumbUrl) return;
            const ph = document.getElementById(_thumbId);
            if (!ph) return;
            ph.style.backgroundImage = `url(${thumbUrl})`;
            ph.style.backgroundSize  = 'cover';
            ph.style.backgroundPosition = 'center';
            ph.innerHTML = `
              <div style="position:absolute;inset:0;background:rgba(0,0,0,.25);"></div>
              <div style="position:relative;width:60px;height:60px;background:rgba(0,0,0,.65);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:1.6em;box-shadow:0 4px 20px rgba(0,0,0,.7);">▶</div>`;
          } catch(e) {}
        })();
      }
    }

    card.addEventListener('mouseenter', () => playSound('hover'));
    grid.appendChild(card);
  });

  agregarEmojisFlotantes();
}

// Reproducir video local desde IDB
async function reproducirVideoLocal(fileId, titulo) {
  try {
    const record = await new Promise((res, rej) => {
      const req = indexedDB.open('ClickPlanetDB', 2);
      req.onsuccess = e => {
        const db = e.target.result;
        const get = db.transaction('files','readonly').objectStore('files').get(fileId);
        get.onsuccess = () => res(get.result);
        get.onerror   = () => rej(new Error('No encontrado'));
      };
      req.onerror = () => rej(new Error('IDB error'));
    });
    if (!record) { showToast('❌ Video no disponible'); return; }
    const stored = record.blob || record;
    const data   = stored.data || stored;
    const blob   = new Blob([data], { type: stored.type || 'video/mp4' });
    const url    = URL.createObjectURL(blob);
    const w = window.open('', '_blank');
    w.document.write(`<!doctype html><html><head><title>${titulo}</title></head>
      <body style="margin:0;background:#000;display:flex;align-items:center;justify-content:center;min-height:100vh">
      <video controls autoplay style="max-width:100%;max-height:100vh" src="${url}"></video>
      </body></html>`);
    // [MEJORA] Liberar ObjectURL cuando la ventana se cierra
    w.addEventListener('unload', () => URL.revokeObjectURL(url));
  } catch(e) {
    showToast('❌ Error al reproducir: ' + e.message);
  }
}


function agregarEventListenersMejorados() {
  document.querySelectorAll('.video-card-mejorada').forEach(card => {
    card.addEventListener('click', function(e) {
      if (e.target.tagName === 'IFRAME') return;
      reproducirVideoMejorado(this, this.getAttribute('data-video-id'));
    });
    card.addEventListener('mouseenter', () => playSound('hover'));
  });
}

function reproducirVideoMejorado(card, videoId) {
  if (videoActual && videoActual !== card) detenerVideoMejorado(videoActual);
  if (card.classList.contains('playing')) { detenerVideoMejorado(card); }
  else { card.classList.add('playing'); videoActual = card; playSound('click'); }
}

function detenerVideoMejorado(card) {
  card.classList.remove('playing');
  if (videoActual === card) videoActual = null;
}

function getCategoryName(cat) {
  return { reciclaje:'Reciclaje', agua:'Agua', naturaleza:'Naturaleza', diversion:'Diversión' }[cat] || cat;
}

function filtrarVideos(categoria, e) {
  if (videoActual) detenerVideoMejorado(videoActual);
  document.querySelectorAll('.btn-categoria').forEach(b => b.classList.remove('active'));
  if (e && e.target) e.target.classList.add('active');
  cargarTodosLosVideosMejorados(categoria);
}

function agregarEmojisFlotantes() {
  const emojis = ['🌍','🌱','💚','🌟','🎯','✨','🚀','🌈'];
  const sec = document.getElementById('cursos');
  document.querySelectorAll('.emoji-float').forEach(e => e.remove());
  for (let i = 0; i < 8; i++) {
    const el = document.createElement('div');
    el.className = 'emoji-float';
    el.textContent = emojis[Math.floor(Math.random() * emojis.length)];
    el.style.left = Math.random() * 100 + 'vw';
    el.style.top = Math.random() * 100 + 'vh';
    el.style.animationDelay = Math.random() * 5 + 's';
    sec.appendChild(el);
  }
}

// Sonido y tema
/* ── Sistema de sonido con Web Audio API ── */
const _audioCtx = (() => { try { return new (window.AudioContext || window.webkitAudioContext)(); } catch(e) { return null; } })();
const sounds = { hover: true, click: true };

function _playTone(freq, dur, vol, type) {
  if (!_audioCtx) return;
  if (_audioCtx.state === 'suspended') _audioCtx.resume();
  const osc = _audioCtx.createOscillator();
  const gain = _audioCtx.createGain();
  osc.type = type || 'sine';
  osc.frequency.setValueAtTime(freq, _audioCtx.currentTime);
  gain.gain.setValueAtTime(vol, _audioCtx.currentTime);
  gain.gain.exponentialRampToValueAtTime(0.001, _audioCtx.currentTime + dur);
  osc.connect(gain); gain.connect(_audioCtx.destination);
  osc.start(); osc.stop(_audioCtx.currentTime + dur);
}
let soundEnabled = true, currentTheme = 'night';

function playSound(type) {
  if (!soundEnabled || !_audioCtx) return;
  try {
    if (type === 'hover') {
      // Soft chime — two gentle sine tones
      _playTone(880, 0.12, 0.06, 'sine');
      setTimeout(() => _playTone(1320, 0.10, 0.04, 'sine'), 40);
    } else if (type === 'click') {
      _playTone(660, 0.15, 0.10, 'sine');
      setTimeout(() => _playTone(990, 0.12, 0.07, 'sine'), 30);
      const f = document.getElementById('soundFeedback');
      f.classList.remove('active');
      setTimeout(() => f.classList.add('active'), 10);
    }
  } catch(e) {}
}

function toggleTheme() {
  const themes = ['night', 'day', 'purple'];
  const icons  = { night: '🦉', day: '🌻', purple: '🔮' };
  const idx = themes.indexOf(currentTheme);
  currentTheme = themes[(idx + 1) % themes.length];
  document.body.setAttribute('data-theme', currentTheme);
  document.getElementById('themeToggle').innerHTML = icons[currentTheme] || '🦉';
  if (typeof switchCursor === 'function') switchCursor(currentTheme);
  playSound('click');
}

function toggleSound() {
  soundEnabled = !soundEnabled;
  const st = document.getElementById('soundToggle');
  const sw = document.getElementById('soundWave');
  if (soundEnabled) { st.innerHTML = '<i class="fas fa-volume-up"></i>'; st.classList.remove('muted'); sw.classList.add('active'); playSound('click'); }
  else { st.innerHTML = '<i class="fas fa-volume-mute"></i>'; st.classList.add('muted'); sw.classList.remove('active'); }
}

