// renderBooksAdmin — async: carga portadas desde IndexedDB
async function renderBooksAdmin() {
  const books = Books.getBooks();
  const grid  = document.getElementById('booksAdminGrid');
  if (!grid) return;
  if (!books.length) { grid.innerHTML = '<p style="color:rgba(184,255,217,0.4);">No hay libros aún. Usa admin.html para agregar.</p>'; return; }

  // Esqueletos
  grid.innerHTML = books.map(b => `
    <div class="book-admin-card" id="bac-${b.id}">
      <div id="bacimg-${b.id}" style="width:80px;height:80px;background:rgba(0,0,0,.3);border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:2em;flex-shrink:0">⏳</div>
      <div class="book-admin-info">
        <span class="book-admin-badge">${b.category}</span>
        <h4>${b.title}</h4>
        <p>${(b.description||'').slice(0,80)}...</p>
        <div class="book-admin-actions">
          <button class="btn-admin-delete" onclick="adminDeleteBook('${b.id}')"><i class="fas fa-trash"></i> Eliminar</button>
          <button class="btn-admin-view" id="bacpdf-${b.id}" ${b.pdfFileId?'':'disabled style="opacity:.4"'}>
            <i class="fas fa-eye"></i> Ver PDF
          </button>
        </div>
      </div>
    </div>`).join('');

  // Cargar portadas e inyectar handlers PDF desde IDB
  for (const b of books) {
    // Portada
    const imgEl = document.getElementById('bacimg-' + b.id);
    if (imgEl) {
      const src = await Books.getFileURL(b.coverFileId);
      const finalSrc = src || b.coverUrl || 'https://cdn-icons-png.flaticon.com/512/2232/2232688.png';
      imgEl.outerHTML = `<img class="book-admin-cover" id="bacimg-${b.id}" src="${finalSrc}" alt="${b.title}" onerror="this.src='https://cdn-icons-png.flaticon.com/512/2232/2232688.png'">`;
    }
    // PDF
    const pdfBtn = document.getElementById('bacpdf-' + b.id);
    if (pdfBtn && b.pdfFileId) {
      pdfBtn.onclick = async () => {
        pdfBtn.disabled = true; pdfBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i>';
        try {
          const url = await Books.getFileURL(b.pdfFileId);
          if (url) { openPdfReader(url, b.title); }
          else { showToast('PDF no encontrado', true); }
        } finally { pdfBtn.disabled = false; pdfBtn.innerHTML = '<i class="fas fa-eye"></i> Ver PDF'; }
      };
    }
  }
}

function renderUsersTable() {
  const users = Auth.getUsers();
  const c = document.getElementById('usersTableContainer');
  if (!users.length) { c.innerHTML = '<p style="color:rgba(184,255,217,0.4);">Sin usuarios aún.</p>'; return; }
  c.innerHTML = `<div class="users-table"><table>
    <thead><tr><th>Avatar</th><th>Nombre</th><th>Usuario</th><th>Rol</th><th>Registro</th></tr></thead>
    <tbody>${users.map(u => `<tr>
      <td style="font-size:1.3em;">${u.avatar||'🌱'}</td>
      <td>${u.displayName}</td>
      <td style="color:rgba(184,255,217,0.5);">@${u.username}</td>
      <td><span style="padding:3px 10px;border-radius:20px;font-size:0.78em;font-weight:600;background:${u.role==='admin'?'rgba(0,255,128,0.15)':'rgba(100,100,255,0.12)'};color:${u.role==='admin'?'#00ff99':'#a0a0ff'};border:1px solid ${u.role==='admin'?'rgba(0,255,128,0.3)':'rgba(100,100,255,0.25)'};">${u.role==='admin'?'🌿 Admin':'🌱 Viewer'}</span></td>
      <td style="color:rgba(184,255,217,0.4);font-size:0.82em;">${new Date(u.createdAt).toLocaleDateString('es-CO')}</td>
    </tr>`).join('')}</tbody></table></div>`;
}

window.adminDeleteBook = async function(id) {
  if (!confirm('¿Eliminar este libro?')) return;
  Books.deleteBook(id);
  await renderBooksAdmin(); renderDashboardInterno(); renderLibrosMain();
  showToast('Libro eliminado.');
};

