// Lee un archivo de IndexedDB y devuelve un blob URL
function _leerArchivoIDB(fileId) {
  return new Promise((resolve) => {
    if (!fileId) return resolve(null);
    try {
      const req = indexedDB.open('ClickPlanetDB', 2);
      req.onerror = () => resolve(null);
      req.onsuccess = e => {
        try {
          const db  = e.target.result;
          const get = db.transaction('files','readonly').objectStore('files').get(fileId);
          get.onerror   = () => resolve(null);
          get.onsuccess = () => {
            const record = get.result;
            if (!record) return resolve(null);
            try {
              const stored = record.blob || record;
              const data   = stored.data  || stored;
              const type   = stored.type  || 'image/jpeg';
              resolve(URL.createObjectURL(new Blob([data], { type })));
            } catch(e) { resolve(null); }
          };
        } catch(e) { resolve(null); }
      };
    } catch(e) { resolve(null); }
  });
}

async function abrirAnimal(id) {
  const a = getAnimalesCompletos().find(x => x.id === id);
  if (!a) return;

  // Foto: mostrar siempre algo en el área de imagen del modal
  const amiImg    = document.getElementById('amiImg');
  const imgWrap   = amiImg ? amiImg.closest('.ami-img-wrap-modal') : null;

  // Placeholder inmediato con fondo degradado y emoji
  amiImg.style.display = 'none';
  if (imgWrap) imgWrap.style.background = 'linear-gradient(160deg,#041a0a,#020e05)';

  // Intentar cargar desde IDB primero, luego img URL
  let fotoUrl = a.img || null;
  if (a.imgFileId) {
    try {
      const url = await _leerArchivoIDB(a.imgFileId);
      if (url) fotoUrl = url;
    } catch(e) {}
  }

  if (fotoUrl) {
    amiImg.onload = () => { amiImg.style.display = 'block'; };
    amiImg.onerror = () => { amiImg.style.display = 'none'; };
    amiImg.src = fotoUrl;
  } else {
    amiImg.style.display = 'none';
  }

  document.getElementById('amiEmoji').textContent = a.emoji || '🐾';
  document.getElementById('amiName').textContent  = a.nombre;
  document.getElementById('amiSci').textContent   = a.cientifico || '';
  document.getElementById('amiDesc').textContent  = a.desc;
  document.getElementById('amiStats').innerHTML   = (a.stats||[]).map(s =>
    `<div class="ami-stat"><div class="sv">${s.v}</div><div class="sk">${s.k}</div></div>`
  ).join('');

  // Video: cargar desde IDB si hay videoFileId, si no ocultar
  const vw = document.getElementById('amiVideoWrap');
  vw.innerHTML = '';
  if (a.videoFileId) {
    vw.style.display = 'block';
    vw.innerHTML = `<div style="display:flex;align-items:center;justify-content:center;padding:20px;background:rgba(0,0,0,.3);border-radius:12px;">
      <div style="font-size:1.5em;animation:bb 1s ease infinite alternate">🎬</div>
      <span style="color:rgba(180,255,200,.5);margin-left:12px;font-size:.85em">Cargando video...</span>
    </div>`;
    // Cargar video desde IDB
    (async () => {
      try {
        const url = await _leerArchivoIDB(a.videoFileId);
        if (url) {
          vw.innerHTML = `<video controls style="width:100%;border-radius:12px;background:#000;display:block;" src="${url}">
            Tu navegador no soporta la reproducción de video.
          </video>`;
        } else {
          vw.style.display = 'none';
        }
      } catch(e) { vw.style.display = 'none'; }
    })();
  } else {
    vw.style.display = 'none';
  }

  document.getElementById('aniModal').classList.add('open');
}

// Leer archivo desde IndexedDB (enciclopedia)
