function getAvatarById(id) { return AVATARES.find(a => a.id === id) || AVATARES[0]; }

// ── Guardar / leer avatar del usuario ────────────────────
function getSavedAvatar() {
  try {
    const s = localStorage.getItem('cp_session');
    if (s) { const sess = JSON.parse(s); if (sess.avatar) return sess.avatar; }
    return localStorage.getItem('cp_avatar') || null;
  } catch(e) { return null; }
}

function saveAvatar(id) {
  try {
    const s = localStorage.getItem('cp_session');
    if (s) {
      const sess = JSON.parse(s);
      sess.avatar = id;
      localStorage.setItem('cp_session', JSON.stringify(sess));
    }
    localStorage.setItem('cp_avatar', id);
  } catch(e) {}
}

// ── Selector de avatar ────────────────────────────────────
let _avatarTmp = null;

function openAvatarSelector() {
  _avatarTmp = getSavedAvatar() || 'aire';
  const grid = document.getElementById('avatarGrid');
  if (grid) {
    grid.innerHTML = AVATARES.map(a => `
      <div class="avatar-opt ${_avatarTmp===a.id?'selected':''}" data-id="${a.id}" onclick="selectAvatar('${a.id}')">
        <img src="${a.img}" alt="${a.nombre}">
        <span>${a.nombre}</span>
        <small>${a.poder}</small>
      </div>`).join('');
  }
  const overlay = document.getElementById('avatarSelector');
  if (overlay) overlay.classList.add('open');
}

function selectAvatar(id) {
  _avatarTmp = id;
  document.querySelectorAll('.avatar-opt').forEach(el => {
    el.classList.toggle('selected', el.dataset.id === id);
  });
}

function confirmarAvatar() {
  const id = _avatarTmp || 'aire';
  saveAvatar(id);
  const overlay = document.getElementById('avatarSelector');
  if (overlay) overlay.classList.remove('open');
  updateAvatarUI();
  if (typeof playSound === 'function') playSound('click');
}

// ── Actualizar UI con el avatar guardado ─────────────────
function updateAvatarUI() {
  const id = getSavedAvatar() || 'aire';
  const av = getAvatarById(id);

  // Burbuja flotante
  const burbuja = document.getElementById('perfilBurbuja');
  if (burbuja) burbuja.classList.add('visible');

  // Imagen en burbuja y tarjeta
  const cpi = document.getElementById('cardPerfilImg');
  if (cpi) cpi.src = av.img;

  // Mostrar botón de perfil en menú
  const perfilBtn = document.getElementById('perfilMenuBtn');
  if (perfilBtn) perfilBtn.style.display = 'block';

  // Nivel en burbuja
  try {
    const s = localStorage.getItem('cp_session');
    const sess = s ? JSON.parse(s) : null;
    const uid  = sess ? sess.id : 'guest';
    const xpKey = `cp_perfil_${uid}_xp`;
    const xp    = (() => { try { const v=localStorage.getItem(xpKey); return v?JSON.parse(v):0; } catch(e){return 0;} })();
    const nv    = typeof getNivel==='function' ? getNivel(xp) : {nombre:'🌱 Explorador'};
    const nEl   = document.getElementById('perfilBtnNivel');
    if (nEl) nEl.textContent = nv.nombre;
    const nEl2  = document.getElementById('perfilBtnNombre');
    if (nEl2 && sess) nEl2.textContent = sess.displayName || sess.username || 'Mi Perfil';
  } catch(e) {}
}

// ── pGet / pSet — helpers para datos por-usuario ──────────
function _perfilUid() {
  try { const s = localStorage.getItem('cp_session'); if(s){ const o=JSON.parse(s); return o.id||'guest'; } } catch(e){}
  return 'guest';
}
function pGet(key, def) {
  try { const v = localStorage.getItem('cp_perfil_'+_perfilUid()+'_'+key); return v!==null ? JSON.parse(v) : def; } catch(e){ return def; }
}
function pSet(key, val) {
  localStorage.setItem('cp_perfil_'+_perfilUid()+'_'+key, JSON.stringify(val));
}

