function getMascotasDesbloqueadas() {
  const xp = pGet('xp', 0);
  const visitas = pGet('visitas', []);
  const insignias = pGet('insignias', []);
  const diasUnicos = new Set(visitas).size;
  return MASCOTAS.filter(m => {
    if (xp < m.reqXP) return false;
    if (diasUnicos < m.reqDias) return false;
    for (const ri of m.reqInsignias) { if (!insignias.includes(ri)) return false; }
    return true;
  });
}

function getMascotaActiva() { return pGet('mascota_activa', 'semilla'); }
function setMascotaActiva(id) {
  const desbloqueadas = getMascotasDesbloqueadas();
  if (!desbloqueadas.find(m => m.id === id)) return;
  pSet('mascota_activa', id);
  renderPerfil();
  showToast('🐾 ¡Mascota cambiada!');
}

