function toggleFavorito(libro) {
  const favs = getFavoritos();
  const idx = favs.findIndex(f => f.titulo === libro.titulo);
  if (idx >= 0) { favs.splice(idx, 1); showToast('💔 Quitado de favoritos'); }
  else { favs.unshift({ ...libro, fechaFav: new Date().toLocaleDateString('es-CO') }); showToast('❤️ ¡Agregado a favoritos!'); darXP(5, 'Favorito'); }
  pSet('favoritos', favs);
  return favs;
}

// ── RANKING de usuarios ──────────────────────────────────
function calcularRanking() {
  const users = Auth.getUsers();
  const ranking = users.map(u => {
    let xp = 0;
    try { const v = localStorage.getItem('cp_perfil_'+u.id+'_xp'); xp = v ? JSON.parse(v) : 0; } catch(e){}
    return { id: u.id, username: u.displayName || u.username, xp, avatar: u.avatar || '🌱' };
  });
  ranking.sort((a, b) => b.xp - a.xp);
  return ranking;
}

