const NIVELES_XP = [
  { min:0,    max:100,  nombre:'🌱 Explorador' },
  { min:100,  max:300,  nombre:'🌿 Guardián' },
  { min:300,  max:600,  nombre:'🌳 Defensor del Bosque' },
  { min:600,  max:1000, nombre:'🦁 Héroe del Planeta' },
  { min:1000, max:1500, nombre:'🦸 Campeón Ecológico' },
  { min:1500, max:2500, nombre:'🌍 Leyenda Verde' },
  { min:2500, max:5000, nombre:'⭐ Embajador Planetario' },
  { min:5000, max:99999, nombre:'💫 Maestro de la Tierra' }
];
function getNivel(xp) {
  for (let i = NIVELES_XP.length - 1; i >= 0; i--) {
    if (xp >= NIVELES_XP[i].min) return NIVELES_XP[i];
  }
  return NIVELES_XP[0];
}

