// ── Misiones semanales ───────────────────────────────────
function getMisiones() {
  const semana = new Date(); semana.setHours(0,0,0,0);
  semana.setDate(semana.getDate() - semana.getDay()); // lunes
  const completadas = pGet('misiones_completadas', []);
  return [
    { id:'m1', texto:'Abre un cuento esta semana',     emoji:'📖', xp:30, completada: completadas.includes('m1') },
    { id:'m2', texto:'Visita la Enciclopedia Animal',  emoji:'🦁', xp:25, completada: completadas.includes('m2') },
    { id:'m3', texto:'Registra 2 acciones ecológicas', emoji:'🌱', xp:40, completada: completadas.includes('m3') },
    { id:'m4', texto:'Entra 3 días seguidos',          emoji:'🔥', xp:50, completada: completadas.includes('m4') },
    { id:'m5', texto:'Explora la Naturaleza Local',    emoji:'🌳', xp:20, completada: completadas.includes('m5') },
  ];
}

// ── Dar XP y verificar insignias ─────────────────────────
function darXP(cantidad, razon) {
  const xp = (pGet('xp', 0)) + cantidad;
  pSet('xp', xp);
  // Verificar insignias automáticamente
  verificarInsignias();
  return xp;
}

function ganarInsignia(id) {
  const ganadas = pGet('insignias', []);
  if (ganadas.includes(id)) return false;
  ganadas.push(id);
  pSet('insignias', ganadas);
  const ins = INSIGNIAS.find(i => i.id === id);
  if (ins) {
    darXP(ins.xp, ins.nombre);
    showToast(`🏅 ¡Insignia desbloqueada! ${ins.emoji} ${ins.nombre}`);
  }
  return true;
}

function verificarInsignias() {
  const xp    = pGet('xp', 0);
  const racha = calcularRacha();
  const huella= pGet('huella', []).length;
  const libros= pGet('libros_leidos', []).length;
  const ganadas = pGet('insignias', []);

  if (!ganadas.includes('bienvenido'))   ganarInsignia('bienvenido');
  if (racha >= 3  && !ganadas.includes('racha3'))  ganarInsignia('racha3');
  if (racha >= 7  && !ganadas.includes('racha7'))  ganarInsignia('racha7');
  if (huella >= 1 && !ganadas.includes('huella1')) ganarInsignia('huella1');
  if (huella >= 5 && !ganadas.includes('huella5')) ganarInsignia('huella5');
  if (libros >= 1 && !ganadas.includes('lector1')) ganarInsignia('lector1');
  if (libros >= 5 && !ganadas.includes('lector5')) ganarInsignia('lector5');
  const avatarId = getSavedAvatar ? getSavedAvatar() : null;
  if (avatarId   && !ganadas.includes('avatar'))   ganarInsignia('avatar');
}

// ── Racha diaria ─────────────────────────────────────────
function registrarVisitaHoy() {
  const hoy     = new Date().toISOString().slice(0,10);
  const visitas = pGet('visitas', []);
  if (!visitas.includes(hoy)) {
    visitas.push(hoy);
    if (visitas.length > 30) visitas.shift(); // guardar solo 30 días
    pSet('visitas', visitas);
    darXP(5, 'Visita diaria');
  }
  verificarInsignias();
}

function calcularRacha() {
  const visitas = pGet('visitas', []).sort();
  if (!visitas.length) return 0;
  let racha = 1, max = 1;
  for (let i = visitas.length-1; i > 0; i--) {
    const d1 = new Date(visitas[i]), d2 = new Date(visitas[i-1]);
    const diff = (d1 - d2) / 86400000;
    if (diff === 1) { racha++; max = Math.max(max, racha); }
    else if (diff > 1) break;
  }
  return racha;
}

// ── Registrar libro leído ─────────────────────────────────
function registrarLibroLeido(bookId, titulo) {
  const lista = pGet('libros_leidos', []);
  if (!lista.find(b => b.id === bookId)) {
    lista.unshift({ id:bookId, titulo, fecha:new Date().toISOString().slice(0,10) });
    if (lista.length > 20) lista.pop();
    pSet('libros_leidos', lista);
    darXP(15, 'Libro leído');
    completarMision('m1');
  }
  verificarInsignias();
}

// ── Completar misión ──────────────────────────────────────
function completarMision(id) {
  const completadas = pGet('misiones_completadas', []);
  if (!completadas.includes(id)) {
    completadas.push(id);
    pSet('misiones_completadas', completadas);
    const m = getMisiones().find(x=>x.id===id);
    if (m) { darXP(m.xp, 'Misión'); showToast(`🎯 ¡Misión completada! +${m.xp} XP`); }
    if (!pGet('insignias',[]).includes('mision1')) ganarInsignia('mision1');
  }
}

// ── Huella verde ─────────────────────────────────────────
function agregarHuella() {
  const input = document.getElementById('huellaInput');
  const texto = input.value.trim();
  if (!texto) return;
  const lista = pGet('huella', []);
  lista.unshift({ texto, fecha: new Date().toLocaleDateString('es-CO') });
  if (lista.length > 50) lista.pop();
  pSet('huella', lista);
  input.value = '';
  darXP(10, 'Huella verde');
  if (lista.length >= 3) completarMision('m3');
  renderHuellaList();
  verificarInsignias();
  // Actualizar stat de eco-acciones
  const ecoEl = document.getElementById('pStatEco');
  if (ecoEl) ecoEl.textContent = lista.length;
  showToast('🌱 ¡Acción registrada! +10 XP');
}

// ── Abrir / Cerrar perfil ─────────────────────────────────
function abrirPerfil() {
  playSound('click');
  document.getElementById('menu').style.display = 'none';
  document.getElementById('perfilOverlay').classList.add('open');
  const b = document.getElementById('perfilBurbuja'); if(b) b.style.opacity = '0';
  renderPerfil();
  // Misión: visitar enciclopedia se marca desde allá
  completarMision('m5'); // naturaleza local visitada = bonus
}

function cerrarPerfil() {
  playSound('click');
  document.getElementById('perfilOverlay').classList.remove('open');
  document.getElementById('menu').style.display = 'block';
  const b = document.getElementById('perfilBurbuja'); if(b) b.style.opacity = '1';
}

function abrirCambioAvatar() {
  cerrarPerfil();
  if (typeof openAvatarSelector === 'function') openAvatarSelector();
}

// ── Render del perfil ─────────────────────────────────────
function renderPerfil() {
  // Sesión
  let session = null;
  try { const s=localStorage.getItem('cp_session'); session=s?JSON.parse(s):null; } catch(e){}
  if (!session) return;

  // Avatar
  const avatarId = getSavedAvatar ? getSavedAvatar() : 'aire';
  const av = typeof getAvatarById==='function' ? getAvatarById(avatarId||'aire') : {img:'', nombre:'Héroe'};
  document.getElementById('perfilAvatar').src    = av.img;
  document.getElementById('perfilNombre').textContent = session.displayName || session.username || 'Explorador';
  document.getElementById('perfilHeroe').textContent  = av.nombre;
  document.getElementById('perfilFecha').textContent  =
    'Miembro desde ' + (session.createdAt ? new Date(session.createdAt).toLocaleDateString('es-CO', {year:'numeric',month:'long'}) : 'hoy');

  // Bio
  const bioEl = document.getElementById('perfilBio');
  const bioEdit = document.getElementById('perfilBioEdit');
  if (bioEl) bioEl.textContent = getBio() || 'Toca ✏️ para escribir tu biografía...';
  if (bioEdit) bioEdit.value = getBio();

  // XP y nivel
  const xp    = pGet('xp', 0);
  const nivel = getNivel(xp);
  const prog  = Math.min(100, Math.round((xp - nivel.min) / (nivel.max - nivel.min) * 100));
  document.getElementById('perfilNivelNombre').textContent = nivel.nombre;
  document.getElementById('perfilXPtxt').textContent       = `${xp} / ${nivel.max} XP`;
  document.getElementById('perfilXPfill').style.width      = prog + '%';

  // Stats — ahora con eco-acciones
  const racha  = calcularRacha();
  const libros = pGet('libros_leidos', []).length;
  const ecoAcc = pGet('huella', []).length;
  const favsCount = getFavoritos().length;
  document.getElementById('pStatXP').textContent    = xp;
  document.getElementById('pStatRacha').textContent = racha;
  document.getElementById('pStatLibros').textContent= libros;
  const ecoEl = document.getElementById('pStatEco');
  if (ecoEl) ecoEl.textContent = ecoAcc;
  const favEl = document.getElementById('pStatFavs');
  if (favEl) favEl.textContent = favsCount;

  // Mascota activa junto al nombre
  const mascotaAct = MASCOTAS.find(m => m.id === getMascotaActiva()) || MASCOTAS[0];
  const mascEl = document.getElementById('perfilMascota');
  if (mascEl) mascEl.textContent = mascotaAct.emoji + ' ' + mascotaAct.nombre;

  // Racha strip (últimos 7 días)
  const visitas = pGet('visitas', []);
  const strip   = document.getElementById('rachaStrip');
  const dias    = ['L','M','X','J','V','S','D'];
  strip.innerHTML = '';
  for (let i=6; i>=0; i--) {
    const d    = new Date(); d.setDate(d.getDate()-i);
    const key  = d.toISOString().slice(0,10);
    const hoy  = i===0;
    const ok   = visitas.includes(key);
    const div  = document.createElement('div');
    div.className = 'racha-dia' + (ok && !hoy ? ' activo' : '') + (hoy && ok ? ' hoy' : '');
    div.innerHTML  = `<span>${dias[d.getDay()]}</span><span>${ok?'✓':''}</span>`;
    strip.appendChild(div);
  }

  // Misiones
  const misLista = document.getElementById('misionesList');
  misLista.innerHTML = getMisiones().map(m => `
    <div class="mision-item ${m.completada ? 'completada' : ''}">
      <div class="mision-check">${m.completada ? '✓' : ''}</div>
      <div class="mision-txt">
        <strong>${m.emoji} ${m.texto}</strong>
        <span>${m.completada ? '¡Completada! 🎉' : 'Pendiente'}</span>
      </div>
      <span class="mision-xp">+${m.xp} XP</span>
    </div>`).join('');

  // Insignias mejoradas con progreso
  renderInsignias();

  // Huella verde
  renderHuellaList();

  // Cuentos favoritos
  renderFavoritos();

  // Ranking
  renderRanking();

  // Mascotas
  renderMascotas();
}

// ── Render insignias mejoradas ────────────────────────────
function renderInsignias() {
  const ganadas = pGet('insignias', []);
  const totalInsignias = INSIGNIAS.length;
  const ganadasCount = ganadas.length;
  const grid = document.getElementById('insigniasGrid');
  // Contador
  let html = `<div class="insignias-counter">🏆 ${ganadasCount} / ${totalInsignias} desbloqueadas</div>`;
  html += '<div class="insignias-grid-inner">';
  html += INSIGNIAS.map(ins => {
    const desbloqueada = ganadas.includes(ins.id);
    return `
    <div class="insignia-item ${desbloqueada ? 'ganada' : 'bloqueada'}" title="${desbloqueada ? ins.desc : '???'}">
      <div class="ii">${ins.emoji}</div>
      <div class="in">${desbloqueada ? ins.nombre : '???'}</div>
      ${!desbloqueada ? '<div class="ins-req">+ '+ins.xp+' XP</div>' : '<div class="ins-xp">✓</div>'}
    </div>`;
  }).join('');
  html += '</div>';
  grid.innerHTML = html;
}

// ── Render favoritos ───────────────────────────────────────
function renderFavoritos() {
  const el = document.getElementById('favoritosList');
  if (!el) return;
  const favs = getFavoritos();
  if (!favs.length) {
    el.innerHTML = '<p class="perfil-empty-msg">Aún no tienes favoritos. ¡Agrega cuentos desde la biblioteca! ❤️</p>';
    return;
  }
  el.innerHTML = favs.slice(0,10).map(f => `
    <div class="favorito-item">
      <div class="fav-emoji">📖</div>
      <div class="fav-info">
        <strong>${f.titulo}</strong>
        <span>❤️ Favorito</span>
      </div>
    </div>`).join('');
}

// ── Render ranking ─────────────────────────────────────────
function renderRanking() {
  const el = document.getElementById('rankingList');
  if (!el) return;
  const ranking = calcularRanking();
  const miId = getMiPosicion();
  const miPos = ranking.findIndex(r => r.id === miId) + 1;
  const top = ranking.slice(0, 10);
  let html = '';
  if (miPos > 0) {
    html += `<div class="ranking-mi-pos">🏅 Tu posición: #${miPos} de ${ranking.length} exploradores</div>`;
  }
  html += '<div class="ranking-list">';
  top.forEach((r, i) => {
    const soyYo = r.id === miId;
    const medals = ['🥇','🥈','🥉'];
    const medal = i < 3 ? medals[i] : `#${i+1}`;
    html += `
    <div class="ranking-item ${soyYo ? 'soy-yo' : ''}">
      <div class="ranking-pos">${medal}</div>
      <div class="ranking-avatar">${r.avatar}</div>
      <div class="ranking-info">
        <strong>${r.username}</strong>
        <span>${r.xp} XP</span>
      </div>
    </div>`;
  });
  html += '</div>';
  el.innerHTML = html;
}

// ── Render mascotas ────────────────────────────────────────
function renderMascotas() {
  const el = document.getElementById('mascotasGrid');
  if (!el) return;
  const desbloqueadas = getMascotasDesbloqueadas();
  const activa = getMascotaActiva();
  let html = '';
  MASCOTAS.forEach(m => {
    const unlocked = desbloqueadas.find(d => d.id === m.id);
    const isActive = m.id === activa;
    let statusText = '';
    if (!unlocked) {
      const faltantes = [];
      if (m.reqXP > 0) faltantes.push(m.reqXP + ' XP');
      if (m.reqDias > 0) faltantes.push(m.reqDias + ' días');
      statusText = faltantes.join(' · ');
    }
    html += `
    <div class="mascota-card ${unlocked ? 'desbloqueada' : 'bloqueada'} ${isActive ? 'activa' : ''}"
         onclick="${unlocked ? "setMascotaActiva('"+m.id+"')" : ''}" title="${unlocked ? m.desc : 'Bloqueada: '+statusText}">
      <div class="mascota-emoji">${unlocked ? m.emoji : '🔒'}</div>
      <div class="mascota-nombre">${unlocked ? m.nombre : '???'}</div>
      <div class="mascota-desc">${unlocked ? (isActive ? '✨ Activa' : m.desc) : statusText}</div>
    </div>`;
  });
  el.innerHTML = html;
}

function renderHuellaList() {
  const lista = pGet('huella', []);
  const el    = document.getElementById('huellaList');
  if (!el) return;
  const totalAcc = lista.length;
  // Mostrar contador total
  const counterEl = document.getElementById('huellaCounter');
  if (counterEl) counterEl.textContent = totalAcc === 1 ? '1 acción registrada' : totalAcc + ' acciones registradas';
  if (!lista.length) {
    el.innerHTML = '<p style="color:rgba(150,255,180,.3);font-size:.78em;padding:4px 0">Aún no has registrado ninguna acción. ¡Empieza hoy! 🌱</p>';
    return;
  }
  el.innerHTML = lista.slice(0,10).map(h => `
    <div class="huella-item">
      ${h.texto}
      <span class="huella-fecha">${h.fecha}</span>
    </div>`).join('');
}

// ── Bio editing ────────────────────────────────────────────
function toggleBioEdit() {
  const bioEl = document.getElementById('perfilBio');
  const bioWrap = document.getElementById('perfilBioWrap');
  const bioEditWrap = document.getElementById('perfilBioEditWrap');
  if (!bioWrap || !bioEditWrap) return;
  const isEditing = bioEditWrap.style.display === 'block';
  if (isEditing) {
    // Guardar
    const inp = document.getElementById('perfilBioEdit');
    if (inp) setBio(inp.value.trim());
    bioWrap.style.display = 'block';
    bioEditWrap.style.display = 'none';
    renderPerfil();
  } else {
    // Editar
    bioWrap.style.display = 'none';
    bioEditWrap.style.display = 'block';
    const inp = document.getElementById('perfilBioEdit');
    if (inp) { inp.value = getBio(); inp.focus(); }
  }
}
window.toggleBioEdit = toggleBioEdit;

// ── Inicializar al cargar ─────────────────────────────────
document.addEventListener('DOMContentLoaded', () => {
  // Registrar visita del día
  const s = localStorage.getItem('cp_session');
  if (s) {
    registrarVisitaHoy();
    verificarInsignias();
  }
  // Tecla Enter en huella
  const hi = document.getElementById('huellaInput');
  if (hi) hi.addEventListener('keydown', e => { if (e.key==='Enter') agregarHuella(); });
});

