// ══════════════════════════════════════════════════════════
// SISTEMA DE AVATARES — funciones completas
// ══════════════════════════════════════════════════════════
let avatarSeleccionado = null;

function getSavedAvatar() {
  try {
    const s = localStorage.getItem('cp_session');
    if (s) { const sess = JSON.parse(s); if (sess.avatar) return sess.avatar; }
    return localStorage.getItem('cp_avatar') || null;
  } catch(e) { return null; }
}

function getAvatarById(id) {
  return AVATARES.find(a => a.id === id) || AVATARES[0];
}

function initAvatarSelector() {
  const grid = document.getElementById('avatarGrid');
  if (!grid) return;
  grid.innerHTML = AVATARES.map(a => `
    <div class="avatar-opt" data-id="${a.id}" onclick="selectAvatar('${a.id}')">
      <img src="${a.img}" alt="${a.nombre}">
      <span>${a.nombre}</span>
      <small>${a.poder}</small>
    </div>`).join('');
  const saved = getSavedAvatar();
  if (saved) selectAvatar(saved, false);
}

function selectAvatar(id, snd = true) {
  avatarSeleccionado = id;
  document.querySelectorAll('.avatar-opt').forEach(el => {
    el.classList.toggle('selected', el.dataset.id === id);
  });
  if (snd && typeof playSound === 'function') playSound('click');
}

function openAvatarSelector() {
  initAvatarSelector();
  const el = document.getElementById('avatarSelector');
  if (el) el.classList.add('open');
}

function closeAvatarSelector() {
  const el = document.getElementById('avatarSelector');
  if (el) el.classList.remove('open');
}

function confirmarAvatar() {
  if (!avatarSeleccionado) avatarSeleccionado = AVATARES[0].id;
  try {
    const s = localStorage.getItem('cp_session');
    if (s) {
      const sess = JSON.parse(s);
      sess.avatar = avatarSeleccionado;
      localStorage.setItem('cp_session', JSON.stringify(sess));
    } else {
      localStorage.setItem('cp_avatar', avatarSeleccionado);
    }
  } catch(e) {}
  closeAvatarSelector();
  updateAvatarUI();
  if (typeof playSound === 'function') playSound('click');
}

// Conectar botón confirmar y botón cambio avatar
document.addEventListener('DOMContentLoaded', () => {
  const btnConf = document.getElementById('btnConfirmAvatar');
  if (btnConf) btnConf.onclick = confirmarAvatar;

  // Mostrar avatar si ya hay sesión
  try {
    const s = localStorage.getItem('cp_session');
    if (s) {
      const saved = getSavedAvatar();
      if (!saved) {
        setTimeout(() => openAvatarSelector(), 800);
      } else {
        updateAvatarUI();
      }
    }
  } catch(e) {}
});

// setupBookForm — panel interno deshabilitado para subir libros
// (usar admin.html para subir libros con IndexedDB)
function setupBookForm() {
  const btn = document.getElementById('btnAddBook');
  if (!btn) return;
  btn.addEventListener('click', () => {
    showToast('⚠️ Para agregar libros usa el panel admin.html', true);
    setTimeout(() => window.open('admin.html', '_blank'), 1000);
  });
}

// ============================================================
// INICIALIZACIÓN COMPLETA
// ============================================================
document.addEventListener('DOMContentLoaded', function() {
  // Init módulos
  Auth.init();
  createAuthParticles();
  createParticles('particles-welcome', 30);
  createParticles('particles-menu', 30);

  // Tema
  document.body.setAttribute('data-theme', currentTheme);

  // Controles originales
  document.getElementById('themeToggle').addEventListener('click', toggleTheme);
  document.getElementById('soundToggle').addEventListener('click', toggleSound);

  // ── Cursores animados por tema ──
  const cursors = {
    night:  { el: document.getElementById('fireflyC'),  ox: 20, oy: 16 },
    day:    { el: document.getElementById('octopusC'),   ox: 20, oy: 14 },
    purple: { el: document.getElementById('batC'),       ox: 22, oy: 14 }
  };
  let activeCursor = null;
  let cursorIdleTimer = null;

  function switchCursor(theme) {
    // Ocultar todos
    Object.values(cursors).forEach(c => { c.el.classList.remove('active'); c.el.classList.remove('idle'); });
    // Activar el correcto
    activeCursor = cursors[theme] || cursors.night;
    activeCursor.el.classList.add('active');
  }
  window.switchCursor = switchCursor;

  // Activar cursor inicial según tema
  switchCursor(currentTheme);

  document.addEventListener('mousemove', (e) => {
    if (!activeCursor) return;
    activeCursor.el.style.left = (e.clientX - activeCursor.ox) + 'px';
    activeCursor.el.style.top = (e.clientY - activeCursor.oy) + 'px';
    activeCursor.el.classList.remove('idle');
    clearTimeout(cursorIdleTimer);
    cursorIdleTimer = setTimeout(() => { if (activeCursor) activeCursor.el.classList.add('idle'); }, 150);
  });

  document.addEventListener('mouseleave', () => { if (activeCursor) activeCursor.el.classList.remove('active'); });
  document.addEventListener('mouseenter', () => { if (activeCursor) activeCursor.el.classList.add('active'); });
  document.getElementById('entrarBtn').addEventListener('click', e => {
    e.preventDefault(); playSound('click');
    document.getElementById('welcome').classList.add('hidden');
    document.getElementById('menu').classList.add('active');
  });
  document.getElementById('botMsg').addEventListener('click', () => { playSound('click'); showNextBotMessage(); });

  // Sonido en elementos interactivos
  document.querySelectorAll('.card, .btn, .bot-img, .bot-message, .theme-toggle, .sound-toggle, .btn-categoria, .btn-volver-mejorado').forEach(el => {
    el.addEventListener('mouseenter', () => playSound('hover'));
    el.addEventListener('click', () => playSound('click'));
  });

  // Videos
  cargarTodosLosVideosMejorados();

  // Aplicar configuración del admin
  applyConfig();

  // Auth tabs
  document.getElementById('tabLogin').addEventListener('click', () => {
    document.getElementById('tabLogin').classList.add('active');
    document.getElementById('tabRegister').classList.remove('active');
    document.getElementById('formLogin').classList.add('active');
    document.getElementById('formRegister').classList.remove('active');
  });
  document.getElementById('tabRegister').addEventListener('click', () => {
    document.getElementById('tabRegister').classList.add('active');
    document.getElementById('tabLogin').classList.remove('active');
    document.getElementById('formRegister').classList.add('active');
    document.getElementById('formLogin').classList.remove('active');
  });

  // Login Enter
  ['loginUser','loginPass'].forEach(id => {
    document.getElementById(id).addEventListener('keydown', e => { if (e.key === 'Enter') document.getElementById('btnLogin').click(); });
  });

  // Login
  document.getElementById('btnLogin').addEventListener('click', () => {
    const u = document.getElementById('loginUser').value.trim();
    const p = document.getElementById('loginPass').value;
    const err = document.getElementById('loginError');
    if (!u || !p) { err.textContent = 'Por favor completa todos los campos.'; err.classList.add('show'); return; }
    const r = Auth.login(u, p);
    if (!r.success) { err.textContent = r.error; err.classList.add('show'); return; }
    err.classList.remove('show');
    hideAuthOverlay();
    updateUserUI(r.session);
    showToast('¡Bienvenido, ' + r.session.displayName + '! 🌿');
  });

  // Registro
  document.getElementById('btnRegister').addEventListener('click', () => {
    const name = document.getElementById('regName').value;
    const u = document.getElementById('regUser').value;
    const p = document.getElementById('regPass').value;
    const err = document.getElementById('registerError');
    const suc = document.getElementById('registerSuccess');
    if (!u || !p) { err.textContent = 'Usuario y contraseña son obligatorios.'; err.classList.add('show'); suc.classList.remove('show'); return; }
    const r = Auth.register(u, p, name);
    if (!r.success) { err.textContent = r.error; err.classList.add('show'); suc.classList.remove('show'); return; }
    err.classList.remove('show');
    suc.textContent = '¡Cuenta creada! Ahora inicia sesión 🌱';
    suc.classList.add('show');
    setTimeout(() => { document.getElementById('tabLogin').click(); document.getElementById('loginUser').value = u; }, 1500);
  });

  // Menú usuario flotante
  const userBtn = document.getElementById('userFloatingBtn');
  userBtn.addEventListener('click', e => { if (e.target.closest('.user-menu-item')) return; userBtn.classList.toggle('open'); });
  document.addEventListener('click', e => { if (!userBtn.contains(e.target)) userBtn.classList.remove('open'); });
  document.getElementById('btnLogout').addEventListener('click', () => {
    Auth.logout(); updateUserUI(null); userBtn.classList.remove('open');
    showAuthOverlay(); showToast('Sesión cerrada. ¡Hasta pronto! 🌍');
  });
  document.getElementById('btnOpenAdmin').addEventListener('click', () => { userBtn.classList.remove('open'); openAdminPanel(); });

  // Admin nav
  document.querySelectorAll('.admin-nav-item[data-section]').forEach(btn => {
    btn.addEventListener('click', function() {
      document.querySelectorAll('.admin-nav-item').forEach(b => b.classList.remove('active'));
      document.querySelectorAll('.admin-section').forEach(s => s.classList.remove('active'));
      this.classList.add('active');
      document.getElementById('section-' + this.dataset.section).classList.add('active');
    });
  });
  document.getElementById('btnCloseAdmin').addEventListener('click', closeAdminPanel);

  // Book form
  setupBookForm();

  // Verificar sesión activa
  const session = Auth.getCurrentSession();
  if (session) { hideAuthOverlay(); updateUserUI(session); }
  else { showAuthOverlay(); }
});

// ══════════════════════════════════════════════
// NOTICIAS VERDE — didáctico para niños
// ══════════════════════════════════════════════
let _nvFiltroActual = 'todos';
let _nvHablando = false;
let _nvUtterance = null;

function abrirNoticiasVerde() {
  playSound('click');
  const sec = document.getElementById('noticiasSeccion');
  sec.style.display = 'flex';
  renderNoticias();
}
function cerrarNoticiasVerde() {
  playSound('click');
  detenerVoz();
  document.getElementById('noticiasSeccion').style.display = 'none';
}

function filtrarNoticias(cat, btn) {
  _nvFiltroActual = cat;
  document.querySelectorAll('.nv-fil').forEach(b => b.classList.remove('active'));
  if (btn) btn.classList.add('active');
  renderNoticias();
}

function renderNoticias() {
  const grid = document.getElementById('noticiasGrid');
  if (!grid) return;
  let noticias = [];
  try { noticias = JSON.parse(localStorage.getItem('cp_news') || '[]'); } catch(e) {}
  if (_nvFiltroActual !== 'todos') noticias = noticias.filter(n => n.category === _nvFiltroActual);

  if (!noticias.length) {
    grid.innerHTML = `
      <div style="text-align:center;padding:70px 20px;color:rgba(255,255,255,.3);">
        <div style="font-size:4em;margin-bottom:16px;">🌿</div>
        <p style="font-size:1.15em;font-weight:600;">¡Aún no hay noticias!</p>
        <p style="font-size:.9em;margin-top:8px;opacity:.7;">El administrador publicará novedades pronto.</p>
      </div>`;
    return;
  }

  const catColor = { naturaleza:'#00ff88', reciclaje:'#ffdd44', agua:'#00ccff', energia:'#ff9f43', clima:'#a29bfe', biodiversidad:'#fd79a8', general:'#74b9ff' };
  const catEmoji = { naturaleza:'🌳', reciclaje:'♻️', agua:'💧', energia:'⚡', clima:'🌤️', biodiversidad:'🦋', general:'🌍' };
  const EMOJIS_REACCION = ['❤️','😮','😄','🌱','👏'];

  grid.innerHTML = noticias.map((n, i) => {
    const color = catColor[n.category] || '#00ff88';
    const emoji = catEmoji[n.category] || '📰';
    const fecha = n.createdAt ? new Date(n.createdAt).toLocaleDateString('es-CO',{day:'numeric',month:'long',year:'numeric'}) : '';
    const likes = _nvGetLikes(n.id);
    const liked = _nvIsLiked(n.id);
    const reacciones = EMOJIS_REACCION.map(e => {
      const cnt = _nvGetReaccion(n.id, e);
      const reacted = _nvIsReacted(n.id, e);
      return `<button class="nv-emoji-btn${reacted?' reacted':''}" onclick="_nvReaccionar('${n.id}','${e}',this)">${e}<span class="nv-emoji-count">${cnt||''}</span></button>`;
    }).join('');
    const leidas = _nvGetLeidas(n.id);
    return `
      <div class="nv-card" id="nvc-${n.id}" style="animation-delay:${i*0.08}s">
        <div class="nv-img-wrap" id="nvimg-${n.id}">
          ${n.imgFileId
            ? `<div style="width:100%;height:220px;background:#0a1a0c;display:flex;align-items:center;justify-content:center;font-size:4em;">${emoji}</div>`
            : `<div class="nv-img-placeholder" style="background:linear-gradient(135deg,${color}18,${color}08)">${emoji}</div>`}
        </div>
        <div class="nv-body">
          <div class="nv-meta">
            <span class="nv-badge" style="background:${color}22;color:${color};border-color:${color}44">${emoji} ${n.category||'general'}</span>
            ${fecha?`<span class="nv-fecha">📅 ${fecha}</span>`:''}
          </div>
          <h2 class="nv-headline">${n.title||'Sin título'}</h2>
          ${n.content?`<p class="nv-texto">${n.content}</p>`:''}
          <!-- Barra de progreso de lectura -->
          <div class="nv-progress-wrap" title="Progreso de lectura">
            <div class="nv-progress-bar" id="nvprog-${n.id}" style="width:${leidas?'100':'0'}%;background:${color}"></div>
          </div>
          <!-- Reacciones emojis -->
          <div class="nv-reacciones">${reacciones}</div>
          <!-- Botones de acción -->
          <div class="nv-acciones">
            <button class="nv-btn-like${liked?' liked':''}" onclick="_nvLike('${n.id}',this)">
              💚 <span id="nvlikes-${n.id}">${likes}</span> Me gusta
            </button>
            <button class="nv-btn-leer" onclick="_nvLeerVoz('${n.id}')">
              🔊 Escuchar
            </button>
            <button class="nv-btn-cuento" onclick="_nvAbrirCuento('${n.id}')">
              📖 Modo Cuento
            </button>
            ${(n.link||n.url)?`<a href="${n.link||n.url}" target="_blank" class="nv-btn-link">🔗 Ver más</a>`:''}
          </div>
        </div>
      </div>`;
  }).join('');

  // Animación de entrada con IntersectionObserver
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add('visible'); observer.unobserve(e.target); } });
  }, { threshold: 0.1 });
  document.querySelectorAll('.nv-card').forEach(c => observer.observe(c));

  // Barra de progreso al hacer scroll dentro de la noticia
  document.querySelectorAll('.nv-card').forEach(card => {
    const id = card.id.replace('nvc-','');
    const secEl = document.getElementById('nvContenido'); /* FIX: scroll ahora está en nvContenido, no en noticiasSeccion */
    const updateProg = () => {
      const rect = card.getBoundingClientRect();
      const secRect = secEl.getBoundingClientRect();
      const visible = Math.min(secRect.bottom, rect.bottom) - Math.max(secRect.top, rect.top);
      const pct = Math.max(0, Math.min(100, (visible / card.offsetHeight) * 150));
      const bar = document.getElementById('nvprog-' + id);
      if (bar && pct > parseInt(bar.style.width||0)) {
        bar.style.width = pct + '%';
        if (pct >= 90) _nvMarcarLeida(id);
      }
    };
    secEl.addEventListener('scroll', updateProg, { passive: true });
  });

  // Cargar imágenes desde IDB
  noticias.forEach(async n => {
    if (!n.imgFileId) return;
    try {
      const url = await getFileURL(n.imgFileId);
      if (!url) return;
      const wrap = document.getElementById('nvimg-' + n.id);
      if (wrap) wrap.innerHTML = `<img src="${url}" style="width:100%;height:220px;object-fit:cover;">`;
    } catch(e) {}
  });
}

// ── Likes ──
function _nvGetLikes(id)  { try { return parseInt(localStorage.getItem('nvlk_'+id)||'0'); } catch(e){ return 0; } }
function _nvIsLiked(id)   { try { return !!localStorage.getItem('nvlkd_'+id); } catch(e){ return false; } }
function _nvLike(id, btn) {
  const liked = _nvIsLiked(id);
  const n = _nvGetLikes(id) + (liked ? -1 : 1);
  localStorage.setItem('nvlk_'+id, n);
  liked ? localStorage.removeItem('nvlkd_'+id) : localStorage.setItem('nvlkd_'+id,'1');
  const span = document.getElementById('nvlikes-'+id);
  if (span) span.textContent = n;
  btn.classList.toggle('liked', !liked);
  if (!liked) { btn.style.transform='scale(1.25)'; setTimeout(()=>btn.style.transform='',300); }
}

// ── Reacciones ──
function _nvGetReaccion(id, emoji) { try { return parseInt(localStorage.getItem('nvr_'+id+'_'+encodeURIComponent(emoji))||'0'); } catch(e){ return 0; } }
function _nvIsReacted(id, emoji)   { try { return !!localStorage.getItem('nvrd_'+id+'_'+encodeURIComponent(emoji)); } catch(e){ return false; } }
function _nvReaccionar(id, emoji, btn) {
  const key  = 'nvr_'+id+'_'+encodeURIComponent(emoji);
  const keyD = 'nvrd_'+id+'_'+encodeURIComponent(emoji);
  const reacted = _nvIsReacted(id, emoji);
  const n = _nvGetReaccion(id, emoji) + (reacted ? -1 : 1);
  localStorage.setItem(key, Math.max(0,n));
  reacted ? localStorage.removeItem(keyD) : localStorage.setItem(keyD,'1');
  const span = btn.querySelector('.nv-emoji-count');
  if (span) span.textContent = n > 0 ? n : '';
  btn.classList.toggle('reacted', !reacted);
  btn.style.transform = 'scale(1.4)';
  setTimeout(() => btn.style.transform = '', 300);
}

// ── Progreso lectura ──
function _nvGetLeidas(id)    { try { return !!localStorage.getItem('nvld_'+id); } catch(e){ return false; } }
function _nvMarcarLeida(id)  { localStorage.setItem('nvld_'+id,'1'); }

// ── Lectura en voz alta — mejor voz española disponible ──
let _nvHablandoActivo = false;

function _mejorVozEspanol() {
  const voces = window.speechSynthesis.getVoices();
  // Orden de preferencia: Google ES, Microsoft ES, cualquier ES
  return voces.find(v => v.lang.startsWith('es') && v.name.toLowerCase().includes('google'))
      || voces.find(v => v.lang.startsWith('es') && v.name.toLowerCase().includes('microsoft'))
      || voces.find(v => v.lang === 'es-US')
      || voces.find(v => v.lang === 'es-ES')
      || voces.find(v => v.lang.startsWith('es'))
      || null;
}

function detenerVoz() {
  if (window.speechSynthesis) window.speechSynthesis.cancel();
  _nvHablandoActivo = false;
  _nvHablando = false;
  document.querySelectorAll('.nv-btn-leer').forEach(b => { b.innerHTML = '🔊 Escuchar'; b.style.background = ''; });
  const vzBtn = document.getElementById('nvVozBtn');
  if (vzBtn) { vzBtn.innerHTML = '🔊 Leer en voz alta'; vzBtn.classList.remove('hablando'); }
}

function _hablarTexto(texto, onEnd) {
  if (!window.speechSynthesis) return;
  window.speechSynthesis.cancel();
  const utt = new SpeechSynthesisUtterance(texto);
  utt.lang  = 'es-CO';
  utt.rate  = 0.87;
  utt.pitch = 1.08;
  // Cargar voces (puede necesitar esperar)
  const asignarVoz = () => {
    const voz = _mejorVozEspanol();
    if (voz) utt.voice = voz;
    utt.onend = () => { if (onEnd) onEnd(); };
    utt.onerror = () => { if (onEnd) onEnd(); };
    window.speechSynthesis.speak(utt);
  };
  if (window.speechSynthesis.getVoices().length > 0) {
    asignarVoz();
  } else {
    window.speechSynthesis.onvoiceschanged = asignarVoz;
  }
}

function _nvLeerVoz(id) {
  if (_nvHablandoActivo) { detenerVoz(); return; }
  let noticias = [];
  try { noticias = JSON.parse(localStorage.getItem('cp_news') || '[]'); } catch(e) {}
  const n = noticias.find(x => x.id === id);
  if (!n) return;
  const texto = (n.title || '') + '. ' + (n.content || '');
  const btn = document.querySelector(`[onclick="_nvLeerVoz('${id}')"]`);
  if (btn) { btn.innerHTML = '⏹ Detener'; btn.style.background = 'rgba(255,80,80,.18)'; }
  _nvHablandoActivo = true;
  _nvHablando = true;
  _hablarTexto(texto, () => {
    _nvHablandoActivo = false;
    _nvHablando = false;
    if (btn) { btn.innerHTML = '🔊 Escuchar'; btn.style.background = ''; }
  });
}


// ── Modo Cuento ──
function _nvAbrirCuento(id) {
  let noticias = [];
  try { noticias = JSON.parse(localStorage.getItem('cp_news')||'[]'); } catch(e) {}
  const n = noticias.find(x => x.id === id);
  if (!n) return;
  const catEmoji = { naturaleza:'🌳', reciclaje:'♻️', agua:'💧', energia:'⚡', clima:'🌤️', biodiversidad:'🦋', general:'🌍' };
  document.getElementById('nvCuentoEmoji').textContent  = catEmoji[n.category]||'📰';
  document.getElementById('nvCuentoTitulo').textContent = n.title||'';
  document.getElementById('nvCuentoTexto').textContent  = n.content||'';
  const img = document.getElementById('nvCuentoImg');
  img.style.display = 'none';
  if (n.imgFileId) {
    getFileURL(n.imgFileId).then(url => { if (url) { img.src=url; img.style.display='block'; } }).catch(()=>{});
  }
  document.getElementById('nvCuentoOverlay').style.display = 'block';
  document.body.style.overflow = 'hidden';
}
function cerrarCuento() {
  detenerVoz();
  document.getElementById('nvCuentoOverlay').style.display = 'none';
  document.body.style.overflow = '';
}
function toggleVozCuento() {
  if (_nvHablandoActivo) { detenerVoz(); return; }
  const titulo = document.getElementById('nvCuentoTitulo').textContent;
  const texto  = document.getElementById('nvCuentoTexto').textContent;
  if (!texto) return;
  const btn = document.getElementById('nvVozBtn');
  if (btn) { btn.innerHTML = '⏹ Detener'; btn.classList.add('hablando'); }
  _nvHablandoActivo = true;
  _nvHablando = true;
  _hablarTexto(titulo + '. ' + texto, () => detenerVoz());
}


// ══════════════════════════════════════════════
// PODCAST VERDE — lee cp_podcast del localStorage
// ══════════════════════════════════════════════
function abrirPodcast() {
  playSound('click');
  const sec = document.getElementById('podcastSeccion');
  sec.style.display = 'flex';
  setTimeout(() => sec.style.opacity = '1', 10);
  renderPodcast();
}
function cerrarPodcast() {
  playSound('click');
  document.getElementById('podcastSeccion').style.display = 'none';
}
function renderPodcast() {
  const grid = document.getElementById('podcastGrid');
  if (!grid) return;
  let podcasts = [];
  try { podcasts = JSON.parse(localStorage.getItem('cp_podcast') || '[]'); } catch(e) {}

  if (!podcasts.length) {
    grid.innerHTML = `
      <div style="text-align:center;padding:60px 20px;color:rgba(255,255,255,.3);">
        <div style="font-size:3em;margin-bottom:16px;">🎧</div>
        <p style="font-size:1.1em;">Aún no hay podcasts publicados.</p>
        <p style="font-size:.85em;margin-top:8px;">El administrador puede agregar podcasts desde el Panel Admin.</p>
      </div>`;
    return;
  }

  grid.innerHTML = podcasts.map(p => {
    const fecha = p.createdAt ? new Date(p.createdAt).toLocaleDateString('es-CO', {day:'numeric',month:'long',year:'numeric'}) : '';
    return `
      <div style="background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.08);border-radius:14px;overflow:hidden;margin-bottom:18px;padding:20px;display:flex;gap:16px;align-items:flex-start;">
        <div style="width:60px;height:60px;border-radius:50%;background:rgba(0,255,128,.15);display:flex;align-items:center;justify-content:center;font-size:1.8em;flex-shrink:0;">🎧</div>
        <div style="flex:1;">
          <h3 style="color:#fff;font-size:1em;margin:0 0 6px;">${p.title||'Sin título'}</h3>
          ${p.description ? `<p style="color:rgba(255,255,255,.5);font-size:.85em;margin:0 0 10px;">${p.description}</p>` : ''}
          ${fecha ? `<span style="color:rgba(255,255,255,.3);font-size:.75em;">${fecha}</span>` : ''}
          ${p.audioFileId ? `<div id="paudio-${p.id}" style="margin-top:10px;"><button onclick="reproducirPodcast('${p.audioFileId}')" style="background:rgba(0,255,128,.15);border:1px solid rgba(0,255,128,.3);color:#00ff80;padding:8px 18px;border-radius:20px;cursor:pointer;font-size:.85em;">▶ Escuchar</button></div>` : ''}
          ${p.url ? `<a href="${p.url}" target="_blank" style="display:inline-block;margin-top:10px;color:#00ff80;font-size:.85em;text-decoration:none;">🔗 Escuchar en línea</a>` : ''}
        </div>
      </div>`;
  }).join('');
}
async function reproducirPodcast(fileId) {
  try {
    const url = await getFileURL(fileId);
    if (!url) return;
    const audio = new Audio(url);
    audio.play();
  } catch(e) { console.error('Error reproduciendo podcast:', e); }
}


// ══════════════════════════════════════════════
// EVENTOS AMBIENTALES 📅 — lee cp_events del localStorage
// ══════════════════════════════════════════════
let _evtFiltroActual = 'todos';

function abrirEventosAmbientales() {
  playSound('click');
  const sec = document.getElementById('eventosSeccion');
  sec.style.display = 'flex';
  renderEventos();
}

function cerrarEventosAmbientales() {
  playSound('click');
  document.getElementById('eventosSeccion').style.display = 'none';
}

function filtrarEventos(cat, btn) {
  _evtFiltroActual = cat;
  document.querySelectorAll('.evt-fil').forEach(b => b.classList.remove('active'));
  if (btn) btn.classList.add('active');
  renderEventos();
}

function renderEventos() {
  const grid = document.getElementById('eventosGrid');
  if (!grid) return;
  let eventos = [];
  try { eventos = JSON.parse(localStorage.getItem('cp_events') || '[]'); } catch(e) {}
  if (_evtFiltroActual !== 'todos') eventos = eventos.filter(e => e.category === _evtFiltroActual);

  if (!eventos.length) {
    grid.innerHTML = `
      <div style="text-align:center;padding:70px 20px;color:rgba(255,255,255,.3);">
        <div style="font-size:4em;margin-bottom:16px;">📅</div>
        <p style="font-size:1.15em;font-weight:600;">¡Aún no hay eventos ambientales!</p>
        <p style="font-size:.9em;margin-top:8px;opacity:.7;">El administrador publicará eventos pronto.</p>
      </div>`;
    return;
  }

  const catColor = { conferencia:'#00ccff', campana:'#ffdd44', taller:'#ff9f43', jornada:'#a29bfe', siembra:'#00ff88', general:'#74b9ff' };
  const catEmoji = { conferencia:'🎤', campana:'📢', taller:'🛠️', jornada:'🏃', siembra:'🌱', general:'📅' };
  const statusMap = {
    proximo:  { label:'Próximo',  bg:'rgba(0,255,128,.12)', color:'#00ff88', border:'rgba(0,255,128,.3)', icon:'🕐' },
    en_curso: { label:'En curso', bg:'rgba(255,200,0,.12)', color:'#ffc800', border:'rgba(255,200,0,.3)', icon:'🔴' },
    finalizado:{ label:'Finalizado', bg:'rgba(150,150,150,.12)', color:'#aaa', border:'rgba(150,150,150,.3)', icon:'✅' },
    cancelado:{ label:'Cancelado', bg:'rgba(255,80,80,.12)', color:'#ff5050', border:'rgba(255,80,80,.3)', icon:'❌' }
  };

  // Ordenar: proximo primero, luego en_curso, luego finalizado, cancelado al final
  const statusOrder = { proximo:0, en_curso:1, finalizado:2, cancelado:3 };
  eventos.sort((a,b) => {
    const oa = statusOrder[a.status] ?? 4;
    const ob = statusOrder[b.status] ?? 4;
    if (oa !== ob) return oa - ob;
    // Dentro del mismo status, ordenar por fecha (más cercana primero)
    return new Date(a.date || 0) - new Date(b.date || 0);
  });

  grid.innerHTML = eventos.map((ev, i) => {
    const color = catColor[ev.category] || '#00ff88';
    const emoji = catEmoji[ev.category] || '📅';
    const status = statusMap[ev.status] || statusMap.proximo;
    const fecha = ev.date ? new Date(ev.date).toLocaleDateString('es-CO',{day:'numeric',month:'long',year:'numeric'}) : '';
    const hora = ev.time || '';
    const ubicacion = ev.location || '';
    const capacidad = ev.capacity || 0;

    return `
      <div class="evt-card" id="evc-${ev.id}" style="animation-delay:${i*0.08}s" onclick="abrirEventoDetalle('${ev.id}')">
        <div class="evt-img-wrap" id="evtimg-${ev.id}">
          ${ev.imgFileId
            ? `<div style="width:100%;height:180px;background:#0a1a0c;display:flex;align-items:center;justify-content:center;font-size:3.5em;">${emoji}</div>`
            : `<div class="evt-img-placeholder" style="background:linear-gradient(135deg,${color}18,${color}08)">${emoji}</div>`}
          <span class="evt-status-badge" style="background:${status.bg};color:${status.color};border-color:${status.border}">${status.icon} ${status.label}</span>
        </div>
        <div class="evt-body">
          <div class="evt-meta-top">
            <span class="evt-badge" style="background:${color}22;color:${color};border-color:${color}44">${emoji} ${ev.category||'general'}</span>
            ${fecha?`<span class="evt-fecha">📅 ${fecha}</span>`:''}
          </div>
          <h2 class="evt-headline">${ev.title||'Sin título'}</h2>
          ${ev.description?`<p class="evt-texto">${ev.description.substring(0,120)}${ev.description.length>120?'…':''}</p>`:''}
          <div class="evt-info-row">
            ${hora?`<span class="evt-info-chip">🕐 ${hora}</span>`:''}
            ${ubicacion?`<span class="evt-info-chip">📍 ${ubicacion}</span>`:''}
            ${capacidad?`<span class="evt-info-chip">👥 Cap: ${capacidad}</span>`:''}
          </div>
          ${ev.link||ev.url?`<a href="${ev.link||ev.url}" target="_blank" class="evt-btn-link" onclick="event.stopPropagation()">🔗 Inscribirse / Más info</a>`:''}
        </div>
      </div>`;
  }).join('');

  // IntersectionObserver para animación de entrada
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add('visible'); observer.unobserve(e.target); } });
  }, { threshold: 0.1 });
  document.querySelectorAll('.evt-card').forEach(c => observer.observe(c));

  // Cargar imágenes desde IndexedDB
  eventos.forEach(async ev => {
    if (!ev.imgFileId) return;
    try {
      const url = await getFileURL(ev.imgFileId);
      if (!url) return;
      const wrap = document.getElementById('evtimg-' + ev.id);
      if (wrap) wrap.innerHTML = `<img src="${url}" style="width:100%;height:180px;object-fit:cover;">`;
    } catch(e) {}
  });
}

function abrirEventoDetalle(id) {
  let eventos = [];
  try { eventos = JSON.parse(localStorage.getItem('cp_events') || '[]'); } catch(e) {}
  const ev = eventos.find(x => x.id === id);
  if (!ev) return;

  const catColor = { conferencia:'#00ccff', campana:'#ffdd44', taller:'#ff9f43', jornada:'#a29bfe', siembra:'#00ff88', general:'#74b9ff' };
  const catEmoji = { conferencia:'🎤', campana:'📢', taller:'🛠️', jornada:'🏃', siembra:'🌱', general:'📅' };
  const statusMap = {
    proximo:  { label:'Próximo',  bg:'rgba(0,255,128,.12)', color:'#00ff88', border:'rgba(0,255,128,.3)', icon:'🕐' },
    en_curso: { label:'En curso', bg:'rgba(255,200,0,.12)', color:'#ffc800', border:'rgba(255,200,0,.3)', icon:'🔴' },
    finalizado:{ label:'Finalizado', bg:'rgba(150,150,150,.12)', color:'#aaa', border:'rgba(150,150,150,.3)', icon:'✅' },
    cancelado:{ label:'Cancelado', bg:'rgba(255,80,80,.12)', color:'#ff5050', border:'rgba(255,80,80,.3)', icon:'❌' }
  };
  const color = catColor[ev.category] || '#00ff88';
  const status = statusMap[ev.status] || statusMap.proximo;

  // Image
  const imgDiv = document.getElementById('evtModalImg');
  if (ev.imgFileId) {
    imgDiv.innerHTML = `<div style="width:100%;height:250px;display:flex;align-items:center;justify-content:center;font-size:5em;background:linear-gradient(135deg,${color}18,${color}08)">${catEmoji[ev.category]||'📅'}</div>`;
    getFileURL(ev.imgFileId).then(url => { if (url) imgDiv.innerHTML = `<img src="${url}" style="width:100%;height:250px;object-fit:cover;">`; }).catch(()=>{});
  } else {
    imgDiv.innerHTML = `<div style="width:100%;height:250px;display:flex;align-items:center;justify-content:center;font-size:5em;background:linear-gradient(135deg,${color}18,${color}08)">${catEmoji[ev.category]||'📅'}</div>`;
  }

  document.getElementById('evtModalBadge').innerHTML = `<span style="padding:4px 12px;border-radius:20px;font-size:.8em;font-weight:600;background:${color}22;color:${color};border:1px solid ${color}44">${catEmoji[ev.category]||'📅'} ${ev.category||'general'}</span>`;
  document.getElementById('evtModalTitle').textContent = ev.title || 'Sin título';

  // Meta info
  let metaHtml = '';
  if (ev.date) metaHtml += `<span>📅 ${new Date(ev.date).toLocaleDateString('es-CO',{weekday:'long',day:'numeric',month:'long',year:'numeric'})}</span>`;
  if (ev.time) metaHtml += `<span>🕐 ${ev.time}</span>`;
  if (ev.location) metaHtml += `<span>📍 ${ev.location}</span>`;
  if (ev.organizer) metaHtml += `<span>🏢 ${ev.organizer}</span>`;
  document.getElementById('evtModalMeta').innerHTML = metaHtml;

  // Status
  document.getElementById('evtModalStatus').innerHTML = `<span style="display:inline-flex;align-items:center;gap:6px;padding:6px 16px;border-radius:20px;font-size:.85em;font-weight:600;background:${status.bg};color:${status.color};border:1px solid ${status.border}">${status.icon} ${status.label}</span>`;

  // Description
  document.getElementById('evtModalDesc').textContent = ev.description || 'Sin descripción disponible.';

  // Capacity
  const capDiv = document.getElementById('evtModalCapacity');
  if (ev.capacity) {
    capDiv.innerHTML = `<div style="margin-top:16px;padding:12px 16px;background:rgba(0,255,128,.06);border:1px solid rgba(0,255,128,.15);border-radius:12px;"><span style="color:rgba(255,255,255,.5);font-size:.85em;">👥 Cupo máximo: </span><strong style="color:#00ff88;font-size:1em;">${ev.capacity} personas</strong></div>`;
  } else { capDiv.innerHTML = ''; }

  // Actions
  const actDiv = document.getElementById('evtModalActions');
  if (ev.link || ev.url) {
    actDiv.innerHTML = `<a href="${ev.link||ev.url}" target="_blank" style="display:inline-flex;align-items:center;gap:8px;margin-top:20px;padding:12px 28px;background:linear-gradient(135deg,#00ff99,#00c87a);border:none;border-radius:14px;color:#001a0a;font-weight:700;font-size:.95em;text-decoration:none;cursor:pointer;transition:all .3s;">🔗 Inscribirme / Más información</a>`;
  } else { actDiv.innerHTML = ''; }

  document.getElementById('evtModal').style.display = 'flex';
  document.body.style.overflow = 'hidden';
  playSound('click');
}

function cerrarEventoDetalle() {
  document.getElementById('evtModal').style.display = 'none';
  document.body.style.overflow = '';
}

// Sincronización en tiempo real con admin.html — agregar a storage listener existente
window.addEventListener('storage', function(e) {
  if (e.key === 'cp_events') {
    if (document.getElementById('eventosSeccion').style.display !== 'none') renderEventos();
  }
});

// ============================================================
// SECCIÓN JUEGOS ECOLÓGICOS
// ============================================================
let _juegosFiltroActual = 'todos';

function abrirJuegos() {
  playSound('click');
  const sec = document.getElementById('juegosSeccion');
  sec.style.display = 'flex';
  renderJuegos();
}

function cerrarJuegos() {
  playSound('click');
  document.getElementById('juegosSeccion').style.display = 'none';
}

function filtrarJuegos(cat, btn) {
  _juegosFiltroActual = cat;
  document.querySelectorAll('.juegos-fil').forEach(b => b.classList.remove('active'));
  if (btn) btn.classList.add('active');
  renderJuegos();
}

async function renderJuegos() {
  const grid = document.getElementById('juegosGrid');
  if (!grid) return;
  let juegos = [];
  try { juegos = JSON.parse(localStorage.getItem('cp_juegos') || '[]'); } catch(e) {}
  if (_juegosFiltroActual !== 'todos') juegos = juegos.filter(j => j.category === _juegosFiltroActual);

  if (!juegos.length) {
    grid.innerHTML = `
      <div style="text-align:center;padding:70px 20px;color:rgba(255,255,255,.3);grid-column:1/-1;">
        <div style="font-size:4em;margin-bottom:16px;">🎮</div>
        <p style="font-size:1.15em;font-weight:600;">¡Aún no hay juegos!</p>
        <p style="font-size:.9em;margin-top:8px;opacity:.7;">El administrador agregará juegos pronto.</p>
      </div>`;
    return;
  }

  const catEmoji = { trivia:'🧠', memoria:'🃏', reciclaje:'♻️', aventura:'🗺️', general:'🎮' };
  grid.innerHTML = juegos.map(j => `
    <div class="juegos-card" onclick="abrirJuego('${j.id}')">
      <div class="juegos-card-img" style="background:${j.bgColor||'linear-gradient(135deg,rgba(0,255,128,.15),rgba(0,200,100,.08))'}">
        <span id="jimg-${j.id}" style="font-size:3.5em;">${j.emoji||catEmoji[j.category]||'🎮'}</span>
      </div>
      <div class="juegos-card-body">
        <h3>${j.title}</h3>
        <p>${j.description||''}</p>
        <div class="juegos-card-meta">
          <span>${catEmoji[j.category]||'🎮'} ${j.category||'general'}</span>
        </div>
      </div>
    </div>
  `).join('');

  // Cargar imágenes desde IndexedDB
  for (const j of juegos) {
    if (!j.imgFileId) continue;
    const span = document.getElementById('jimg-' + j.id);
    if (!span) continue;
    try {
      const db = await new Promise((res, rej) => {
        const r = indexedDB.open('ClickPlanetDB', 2);
        r.onsuccess = e => res(e.target.result);
        r.onerror = e => rej(e.target.error);
      });
      const url = await new Promise(res => {
        const tx = db.transaction('files','readonly');
        const store = tx.objectStore('files');
        const getReq = store.get(j.imgFileId);
        getReq.onsuccess = () => {
          const record = getReq.result;
          if (!record) { res(null); return; }
          const entry = record.blob || record;
          const data = entry.data || entry;
          const blob = new Blob([data], { type: entry.type || 'image/png' });
          res(URL.createObjectURL(blob));
        };
        getReq.onerror = () => res(null);
      });
      if (url) {
        const parent = span.parentElement;
        if (parent) {
          parent.innerHTML = `<img src="${url}" alt="${j.title}" style="width:100%;height:100%;object-fit:cover;border-radius:18px 18px 0 0;" onerror="this.outerHTML='<span style=font-size:3.5em>${j.emoji||'🎮'}</span>'">`;
        }
      }
    } catch(e) {}
  }
}

function abrirJuego(id) {
  let juegos = [];
  try { juegos = JSON.parse(localStorage.getItem('cp_juegos') || '[]'); } catch(e) {}
  const j = juegos.find(g => g.id === id);
  if (!j) { showToast('Juego no disponible', true); return; }
  if (j.htmlFileId) {
    // Cargar HTML desde IndexedDB y abrir en nueva pestaña
    const req = indexedDB.open('ClickPlanetDB', 2);
    req.onsuccess = function() {
      const db = req.result;
      const tx = db.transaction('files', 'readonly');
      const store = tx.objectStore('files');
      const getReq = store.get(j.htmlFileId);
      getReq.onsuccess = function() {
        const record = getReq.result;
        if (!record) { showToast('❌ Archivo del juego no encontrado', true); return; }
        const stored = record.blob || record;
        const data = stored.data || stored;
        const text = typeof data === 'string' ? data : new TextDecoder().decode(new Uint8Array(data));
        const w = window.open('', '_blank');
        w.document.write(text);
        w.document.close();
      };
      getReq.onerror = function() { showToast('❌ Error al cargar el juego', true); };
    };
  } else if (j.url) {
    window.open(j.url, '_blank');
  } else {
    showToast('Este juego aún no está disponible');
  }
}

// Sincronización juegos con admin
window.addEventListener('storage', function(e) {
  if (e.key === 'cp_juegos') {
    if (document.getElementById('juegosSeccion').style.display !== 'none') renderJuegos();
  }
});

